#!/usr/bin/env -S python3

import tkinter as tk
from colorsys import hsv_to_rgb, rgb_to_hsv
from tkinter import ttk
import math

cw_b64 = ""

def clamp(x):
    return int(max(0, min(x, 255)))


def rgb2hex(r, g, b):
    return "#{0:02x}{1:02x}{2:02x}".format((r), clamp(g), clamp(b))


def hex2rgb(h: str):
    h = h.lstrip("#")
    return tuple( int(h[i : i + 2], 16) for i in (0, 2, 4,))


def get_contrast_color(r, g, b):
    # Calculate luminance
    luminance = (0.299 * r + 0.587 * g + 0.114 * b) / 255

    # Return black for light backgrounds, white for dark backgrounds
    return (0, 0, 0) if luminance > 0.5 else (255, 255, 255)

class color_selector(tk.Canvas):
    bt_height = 20
    cw_sel_radius = 6
    bt_sel_width = 4
    bt_displacement = 5

    def __init__(self, *args, **kwarg):
        hsv = kwarg["hsv"]
        del kwarg["hsv"]

        super().__init__(*args, **kwarg)

        width = int(self["width"])

        self.h, self.s, self.v = hsv

        self.colorwheel = tk.PhotoImage(data=cw_b64)
        self.brightness = tk.PhotoImage(width=width,height=color_selector.bt_height)
        self.brightness.put(self.draw_brightness(self.h, self.s))

        self.create_image(
            0, 0, image=self.colorwheel, anchor="nw", tags=("colorwheel",)
        )
        self.create_image(
            0, width + 5, image=self.brightness, anchor="nw", tags=("brightness",)
        )

        r,g,b = hsv_to_rgb(self.h,self.s,self.v)

        self.create_oval(
            width // 2 - color_selector.cw_sel_radius,
            width // 2 - color_selector.cw_sel_radius,
            width // 2 + color_selector.cw_sel_radius,
            width // 2 + color_selector.cw_sel_radius,
            fill=rgb2hex(int(r*255),int(b*255),int(b*255)),
            outline="black",
            width=1,
            tags=("sel_cw"),
        )

        self.create_rectangle(
            width // 2 - color_selector.bt_sel_width,
            width + color_selector.bt_displacement - 2,
            width // 2 + color_selector.bt_sel_width,
            width + color_selector.bt_displacement + self.brightness.height() + 2,
            fill=rgb2hex(int(r*255),int(b*255),int(b*255)),
            outline="black",
            width=1,
            tags=("sel_bt"),
        )

        self.change_hsv(self.h,self.s,self.v)

        self.tag_bind("colorwheel", "<Button-1>", self.colorwheel_click)
        self.tag_bind("brightness", "<Button-1>", self.brightness_click)

        self.tag_bind("colorwheel", "<B1-Motion>", self.colorwheel_move)
        self.tag_bind("brightness", "<B1-Motion>", self.brightness_move)

        self.tag_bind("sel_cw", "<B1-Motion>", self.colorwheel_move)
        self.tag_bind("sel_bt", "<B1-Motion>", self.brightness_move)

    def draw_brightness(self, h: float, s: float) -> str:
        width = int(self["width"])
        height = color_selector.bt_height
        data = []

        for y in range(height):
            row = [ ]
            for x in range(width):
                if width > 1:
                    v = x / (width - 1)
                else:
                    v = 0.0

                r, g, b = hsv_to_rgb(h, s, v)
                r_byte = clamp(int(r * 255 + 0.5))
                g_byte = clamp(int(g * 255 + 0.5))
                b_byte = clamp(int(b * 255 + 0.5))
                row.append(rgb2hex(r_byte,g_byte,b_byte))

            data.append("{" + " ".join(row) + "} ")

        return " ".join(data)


    def colorwheel_click(self, e):
        width = int(self["width"])
        x, y = e.x, e.y
        cx, cy = width // 2, width // 2
        R = width / 2
        d = math.hypot(x - cx, y - cy)
        if d <= R:
            self.moveto(
                "sel_cw",
                e.x - color_selector.cw_sel_radius,
                e.y - color_selector.cw_sel_radius,
            )
            self.h = math.atan2(y - cy, x - cx)
            self.h = 2 * math.pi + self.h if self.h < 0 else self.h
            self.h = self.h / 2 / math.pi
            self.s = d / R

            r,g,b = hsv_to_rgb(self.h,self.s,1.0)

            self.itemconfig('sel_cw',fill=rgb2hex(int(r*255),int(g*255),int(b*255)),
                                     outline=rgb2hex(*get_contrast_color(int(r*255),int(g*255),int(b*255))))

            r,g,b = hsv_to_rgb(self.h,self.s,self.v)

            self.itemconfig('sel_bt',fill=rgb2hex(int(r*255),int(g*255),int(b*255)),
                                        outline=rgb2hex(*get_contrast_color(int(r*255),int(g*255),int(b*255))))

            self.brightness = tk.PhotoImage(width=width,height=color_selector.bt_height)
            self.brightness.put(self.draw_brightness(self.h, self.s))
            self.itemconfig("brightness", image=self.brightness)

            self.event_generate("<<ColorChanged>>")
        pass

    def colorwheel_move(self, e):
        width = int(self["width"])
        x, y = e.x, e.y
        cx, cy = width // 2, width // 2
        R = width / 2
        px1, py1, px2, py2 = self.coords("sel_cw")
        px = px1 + (px2 - px1) // 2
        py = py1 + (py2 - py1) // 2

        d = math.hypot(x - cx, y - cy)
        if d <= R:
            self.h = math.atan2(y - cy, x - cx)
            self.h = 2 * math.pi + self.h if self.h < 0 else self.h
            self.h = self.h / 2 / math.pi
            self.s = d / R
        else:
            a = math.atan2(y - cy, x - cx)
            x, y = cx + int(math.floor(R * math.cos(a))), cy + int(math.floor(R * math.sin(a)))

            self.h = a
            self.h = 2 * math.pi + self.h if self.h < 0 else self.h
            self.h = self.h / 2 / math.pi
            self.s = 1.0

        self.move(
            "sel_cw",
            x - px,
            y - py,
        )

        r,g,b = hsv_to_rgb(self.h,self.s,1.0)

        self.itemconfig('sel_cw',fill=rgb2hex(int(r*255),int(g*255),int(b*255)),
                                    outline=rgb2hex(*get_contrast_color(int(r*255),int(g*255),int(b*255))))

        r,g,b = hsv_to_rgb(self.h,self.s,self.v)

        self.itemconfig('sel_bt',fill=rgb2hex(int(r*255),int(g*255),int(b*255)),
                                    outline=rgb2hex(*get_contrast_color(int(r*255),int(g*255),int(b*255))))

        self.brightness = tk.PhotoImage(width=width,height=color_selector.bt_height)
        self.brightness.put(self.draw_brightness(self.h, self.s))
        self.itemconfig("brightness", image=self.brightness)

        self.event_generate("<<ColorChanged>>")
        pass

    def brightness_click(self, e):
        width = int(self["width"])
        self.moveto(
            "sel_bt",
            e.x - color_selector.bt_sel_width,
            width + color_selector.bt_displacement - 2,
        )
        self.v = e.x / width

        r,g,b = hsv_to_rgb(self.h,self.s,self.v)

        self.itemconfig('sel_bt',fill=rgb2hex(int(r*255),int(g*255),int(b*255)),
                                 outline=rgb2hex(*get_contrast_color(int(r*255),int(g*255),int(b*255))))

        self.event_generate("<<ColorChanged>>")

    def brightness_move(self, e):
        width = int(self["width"])
        px1, _, px2, _ = self.coords("sel_bt")
        px = px1 + (px2 - px1) // 2

        if e.x >= 0 and e.x <= width:
            self.move("sel_bt", e.x - px, 0)
            self.v = e.x / width
        elif e.x < 0:
            self.move("sel_bt", 0 - px, 0)
            self.v = 0.0
        elif e.x > width:
            self.move("sel_bt", width - px, 0)
            self.v = 1.0

        r,g,b = hsv_to_rgb(self.h,self.s,self.v)

        self.itemconfig('sel_bt',fill=rgb2hex(int(r*255),int(g*255),int(b*255)),
                                    outline=rgb2hex(*get_contrast_color(int(r*255),int(g*255),int(b*255))))
        self.event_generate("<<ColorChanged>>")

    def change_hsv(self, h, s, v):
        self.h = h
        self.s = s
        self.v = v

        width = int(self["width"])
        cx, cy = width // 2, width // 2
        R = width / 2

        d = self.s * R
        theta = self.h * 2 * math.pi
        x = cx + d * math.cos(theta)
        y = cy + d * math.sin(theta)

        self.moveto(
            "sel_cw",
            x - color_selector.cw_sel_radius,
            y - color_selector.cw_sel_radius,
        )

        r,g,b = hsv_to_rgb(self.h,self.s,1.0)

        self.itemconfig('sel_cw',fill=rgb2hex(int(r*255),int(g*255),int(b*255)),
                                 outline=rgb2hex(*get_contrast_color(int(r*255),int(g*255),int(b*255))))

#        self.brightness = ImageTk.PhotoImage(self.draw_brightness(self.h, self.s))
        self.brightness = tk.PhotoImage(width=width,height=color_selector.bt_height)
        self.brightness.put(self.draw_brightness(self.h, self.s))
        self.itemconfig("brightness", image=self.brightness)

        px1, _, px2, _ = self.coords("sel_bt")
        px = px1 + (px2 - px1) // 2

        x = self.v * width

        self.move("sel_bt", x - px, 0)

        r,g,b = hsv_to_rgb(self.h,self.s,self.v)

        self.itemconfig('sel_bt',fill=rgb2hex(int(r*255),int(g*255),int(b*255)),
                                 outline=rgb2hex(*get_contrast_color(int(r*255),int(g*255),int(b*255))))
        pass


class hsv_cw_dialog(tk.Toplevel):
    def __init__(self, *args, **kwargs):
        color = kwargs["color"]
        del kwargs["color"]

        super().__init__(*args, *kwargs)
        self.selected_color = None

        r,g,b = hex2rgb(color)
        hsv= rgb_to_hsv(r/255,g/255,b/255)

        self.cs = color_selector(self, hsv=hsv, width=300, height=330)
        self.cs.pack()

        self.h_var = tk.IntVar()
        self.s_var = tk.IntVar()
        self.v_var = tk.IntVar()

        self.r_var = tk.IntVar()
        self.g_var = tk.IntVar()
        self.b_var = tk.IntVar()

        self.hex_var = tk.StringVar()

        # Register the validation command with the '%P' substitution code
        self.vcmd_rgb = (self.register(self.validate_rgb), '%P')
        self.vcmd_h   = (self.register(self.validate_h), '%P')
        self.vcmd_sv  = (self.register(self.validate_sv), '%P')

        self.hex_frame = ttk.Frame(self)
        self.hex_txt = tk.Entry(
            self.hex_frame,
            textvariable=self.hex_var,
            bd=0,
            justify="center",
            state="readonly",
            highlightthickness=0,
        )
        self.hex_txt.pack(side="left", expand=True, fill="x")
        self.hex_frame.pack(padx=5, pady=(0, 5), expand=True, fill="x")

        self.hsv_frame = ttk.Frame(self)
        self.h_lab = ttk.Label(self.hsv_frame, text="H:", width=3)
        self.h_lab.pack(side="left")
        self.h_txt = ttk.Spinbox(
            self.hsv_frame,
            from_=0,
            to=360,
            increment=1,
            width=5,
            textvariable=self.h_var,
            validate='key',
            validatecommand=self.vcmd_h
        )
        self.h_txt.pack(side="left")

        self.s_lab = ttk.Label(self.hsv_frame, text="S:", width=3)
        self.s_lab.pack(side="left")
        self.s_txt = ttk.Spinbox(
            self.hsv_frame,
            from_=0,
            to=100,
            increment=1,
            width=5,
            textvariable=self.s_var,
            validate='key',
            validatecommand=self.vcmd_sv
        )
        self.s_txt.pack(side="left")

        self.v_lab = ttk.Label(self.hsv_frame, text="V:", width=3)
        self.v_lab.pack(side="left")
        self.v_txt = ttk.Spinbox(
            self.hsv_frame,
            from_=0,
            to=100,
            increment=1,
            width=5,
            textvariable=self.v_var,
            validate='key',
            validatecommand=self.vcmd_sv
        )
        self.v_txt.pack(side="left")
        self.hsv_frame.pack(pady=(0, 5))

        self.rgb_frame = ttk.Frame(self)
        self.r_lab = ttk.Label(self.rgb_frame, text="R:", width=3)
        self.r_lab.pack(side="left")
        self.r_txt = ttk.Spinbox(
            self.rgb_frame,
            from_=0,
            to=255,
            increment=1,
            width=5,
            textvariable=self.r_var,
            validate='key',
            validatecommand=self.vcmd_rgb
        )
        self.r_txt.pack(side="left")

        self.g_lab = ttk.Label(self.rgb_frame, text="G:", width=3)
        self.g_lab.pack(side="left")
        self.g_txt = ttk.Spinbox(
            self.rgb_frame,
            from_=0,
            to=255,
            increment=1,
            width=5,
            textvariable=self.g_var,
            validate='key',
            validatecommand=self.vcmd_rgb
        )
        self.g_txt.pack(side="left")

        self.b_lab = ttk.Label(self.rgb_frame, text="B:", width=3)
        self.b_lab.pack(side="left")
        self.b_txt = ttk.Spinbox(
            self.rgb_frame,
            from_=0,
            to=255,
            increment=1,
            width=5,
            textvariable=self.b_var,
            validate='key',
            validatecommand=self.vcmd_rgb
        )
        self.b_txt.pack(side="left")
        self.rgb_frame.pack(padx=5, pady=(0, 5))

        self.but_frame = ttk.Frame(self)
        self.but_ok = ttk.Button(self.but_frame, text="Ok", command=self.ok)
        self.but_ok.pack(side="left", expand=True, fill="x", padx=(0, 5))
        self.but_cancel = ttk.Button(self.but_frame, text="Cancel", command=self.cancel)
        self.but_cancel.pack(side="left", expand=True, fill="x")
        self.but_frame.pack(padx=5, pady=(0, 5), expand=True, fill="x")

        self.cs.bind("<<ColorChanged>>", self.color_changed)

        self.h_txt.focus_set()

        self.h_id = self.h_var.trace_add("write", self.hsv_changed)
        self.s_id = self.s_var.trace_add("write", self.hsv_changed)
        self.v_id = self.v_var.trace_add("write", self.hsv_changed)

        self.r_id = self.r_var.trace_add("write", self.rgb_changed)
        self.g_id = self.g_var.trace_add("write", self.rgb_changed)
        self.b_id = self.b_var.trace_add("write", self.rgb_changed)

        self.color_changed(None)


    def show_modal(self):
        self.resizable(False, False)

        if self._windowingsystem == "aqua":
            self.tk.call(
                "::tk::unsupported::MacWindowStyle", "style", self, "moveableModal", ""
            )
        elif self._windowingsystem == "x11":
            self.wm_attributes("-type", "dialog")

        self.wait_visibility()
        self.grab_set()
        self.wait_window(self)

    def color_changed(self, e):
        self.h_var.trace_remove("write",self.h_id)
        self.s_var.trace_remove("write",self.s_id)
        self.v_var.trace_remove("write",self.v_id)

        self.h_var.set(int(self.cs.h * 360))
        self.s_var.set(int(self.cs.s * 100))
        self.v_var.set(int(self.cs.v * 100))

        self.h_id = self.h_var.trace_add("write",self.hsv_changed)
        self.s_id = self.s_var.trace_add("write",self.hsv_changed)
        self.v_id = self.v_var.trace_add("write",self.hsv_changed)

        self.r_var.trace_remove("write",self.r_id)
        self.g_var.trace_remove("write",self.g_id)
        self.b_var.trace_remove("write",self.b_id)

        r, g, b = hsv_to_rgb(self.cs.h, self.cs.s, self.cs.v)
        self.r_var.set(int(r * 255))
        self.g_var.set(int(g * 255))
        self.b_var.set(int(b * 255))

        self.r_id = self.r_var.trace_add("write",self.rgb_changed)
        self.g_id = self.g_var.trace_add("write",self.rgb_changed)
        self.b_id = self.b_var.trace_add("write",self.rgb_changed)

        self.hex_var.set(rgb2hex(int(r * 255), int(g * 255), int(b * 255)))
        self.hex_txt["readonlybackground"] = self.hex_var.get()
        self.hex_txt["fg"] = rgb2hex(
            *get_contrast_color(int(r * 255), int(g * 255), int(b * 255))
        )

    def hsv_changed(self,*args):
        try:
            h = self.h_var.get()
            s = self.s_var.get()
            v = self.v_var.get()

            self.cs.change_hsv(
                h / 360, s / 100, v / 100
            )

            r, g, b = hsv_to_rgb(self.cs.h, self.cs.s, self.cs.v)

            self.r_var.trace_remove("write",self.r_id)
            self.g_var.trace_remove("write",self.g_id)
            self.b_var.trace_remove("write",self.b_id)

            self.r_var.set(int(r * 255))
            self.g_var.set(int(g * 255))
            self.b_var.set(int(b * 255))

            self.r_id = self.r_var.trace_add("write",self.rgb_changed)
            self.g_id = self.g_var.trace_add("write",self.rgb_changed)
            self.b_id = self.b_var.trace_add("write",self.rgb_changed)

            self.hex_var.set(rgb2hex(int(r * 255), int(g * 255), int(b * 255)))
            self.hex_txt["readonlybackground"] = self.hex_var.get()
            self.hex_txt["fg"] = rgb2hex(
                *get_contrast_color(int(r * 255), int(g * 255), int(b * 255))
            )
        except tk.TclError:
            pass

    def rgb_changed(self,*args):
        try:
            r = self.r_var.get()
            g = self.g_var.get()
            b = self.b_var.get()

            h, s, v = rgb_to_hsv(r/255, g/255, b/255)

            self.h_var.trace_remove("write",self.h_id)
            self.s_var.trace_remove("write",self.s_id)
            self.v_var.trace_remove("write",self.v_id)

            self.h_var.set(int(h*360))
            self.s_var.set(int(s*100))
            self.v_var.set(int(v*100))

            self.h_id = self.h_var.trace_add("write",self.hsv_changed)
            self.s_id = self.s_var.trace_add("write",self.hsv_changed)
            self.v_id = self.v_var.trace_add("write",self.hsv_changed)

            self.cs.change_hsv(
                self.h_var.get() / 360, self.s_var.get() / 100, self.v_var.get() / 100
            )

            self.hex_var.set(rgb2hex(r, g, b ))
            self.hex_txt["readonlybackground"] = self.hex_var.get()
            self.hex_txt["fg"] = rgb2hex(
                *get_contrast_color(r, g, b)
            )
        except tk.TclError:
            pass

    def validate_rgb(self,new_value):
        """Validates if new_value is an integer between 0 and 255 or empty (for backspace)"""
        if new_value == "":
            return True
        try:
            val = int(new_value)
            return 0 <= val <= 255
        except ValueError:
            return False

    def validate_h(self,new_value):
        """Validates if new_value is an integer between 0 and 360 or empty (for backspace)"""
        if new_value == "":
            return True
        try:
            val = int(new_value)
            return 0 <= val <= 360
        except ValueError:
            return False

    def validate_sv(self,new_value):
        """Validates if new_value is an integer between 0 and 100 or empty (for backspace)"""
        if new_value == "":
            return True
        try:
            val = int(new_value)
            return 0 <= val <= 100
        except ValueError:
            return False

    def ok(self):
        self.selected_color = {
            "hex": self.hex_var.get(),
            "hsv": (self.h_var.get(), self.s_var.get(), self.v_var.get()),
            "rgb": (self.r_var.get(), self.g_var.get(), self.b_var.get()),
        }
        self.grab_release()
        self.destroy()

    def cancel(self):
        self.grab_release()
        self.destroy()


def show_hsv_cw_dialog(parent,title="Color Dialog",color="#ffffff"):
    c = hsv_cw_dialog(parent,color=color)
    c.title(title)
    c.show_modal()
    return c.selected_color

if __name__ == "__main__":
    root = tk.Tk()
    b = tk.Button(root, text="Select Color")

    def get_color(parent):
        color = show_hsv_cw_dialog(parent,color=parent["bg"])
        if color:
            parent["bg"] = color["hex"]

    b["command"] = lambda: get_color(b)
    b.pack()

    tk.mainloop()
